class NotificationRegistry {
    private final Map<String, Supplier<Notification>> registry = new HashMap<>();

    public NotificationRegistry() {
        // Default registrations
        registry.put("EMAIL", EmailNotification::new);
        registry.put("SMS", SMSNotification::new);
        registry.put("PUSH", PushNotification::new);
    }

    public void register(String key, Supplier<Notification> creator) {
        registry.put(key, creator);
    }

    public Notification create(String key) {
        Supplier<Notification> supplier = registry.get(key);
        if (supplier == null) throw new IllegalArgumentException("Unknown: " + key);
        return supplier.get();
    }

    public Set<String> getRegisteredTypes() {
        return Collections.unmodifiableSet(registry.keySet());
    }
}

public class Main {
    public static void main(String[] args) {
        NotificationRegistry registry = new NotificationRegistry();

        // Use built-in types
        registry.create("EMAIL").send("Order confirmed!");
        registry.create("SMS").send("OTP: 1234");

        // Dynamically register Telegram -- no factory code modified!
        registry.register("TELEGRAM", TelegramNotification::new);
        registry.create("TELEGRAM").send("Welcome to our channel!");

        System.out.println("Registered types: " + registry.getRegisteredTypes());
    }
