// FACTORY METHOD: Creation as a HOOK inside a service class.
// Subclasses decide WHAT to create. Service owns the shared workflow.
// USE WHEN: creation needs PRIVATE knowledge per type (config, keys)
// AND the service has SHARED logic around the product (log, retry, audit).

import java.util.*;

// Product Interface -- same as Simple Factory
interface Notification {
    void send(String message);
    String getChannel();
}

// Concrete Products -- each needs PRIVATE config to construct
class EmailNotification implements Notification {
    private String smtpHost;
    EmailNotification(String smtpHost) { this.smtpHost = smtpHost; }
    public void send(String message) {
        System.out.println("[EMAIL via " + smtpHost + "] " + message);
    }
    public String getChannel() { return "EMAIL"; }
}

class SMSNotification implements Notification {
    private String apiKey;
    SMSNotification(String apiKey) { this.apiKey = apiKey; }
    public void send(String message) {
        System.out.println("[SMS via " + apiKey.substring(0,4) + "***] " + message);
    }
    public String getChannel() { return "SMS"; }
}

// ===== THE ABSTRACT CREATOR (Service) =====
// WHY this class exists:
// 1. createNotification() = FACTORY METHOD -- subclasses override
// 2. sendNotification() = SHARED orchestration -- written ONCE
// Without this, every service duplicates validate/log/audit.
abstract class NotificationService {
    // Factory Method -- subclasses fill in WHAT to create
    protected abstract Notification createNotification();

    // Template Method -- shared workflow using the created product
    public final void sendNotification(String message) {
        validate(message);
        Notification n = createNotification(); // HOOK: subclass decides
        n.send(message);
        log(n.getChannel(), message);
        audit(n.getChannel());
    }

    private void validate(String msg) {
        System.out.println("  Validating: non-empty=" + !msg.isEmpty());
    }
    private void log(String ch, String msg) {
        System.out.println("  [LOG] " + ch + " | " + msg.substring(0, Math.min(20, msg.length())) + "...");
    }
    private void audit(String ch) {
        System.out.println("  [AUDIT] " + ch + " dispatched");
    }
}

// Concrete Creators -- each owns PRIVATE creation knowledge
class EmailNotificationService extends NotificationService {
    protected Notification createNotification() {
        // PRIVATE KNOWLEDGE: only EmailService knows SMTP config
        String host = System.getenv().getOrDefault("SMTP_HOST", "smtp.walmart.com");
        System.out.println("  Loading SMTP config: " + host);
        return new EmailNotification(host);
    }
}

class SMSNotificationService extends NotificationService {
    protected Notification createNotification() {
        // PRIVATE KNOWLEDGE: only SMSService knows the API key source
        String apiKey = "twilio-9x8z";
        System.out.println("  Loading SMS API key from vault");
        return new SMSNotification(apiKey);
    }
}

// Client: holds abstract service reference
public class Main {
    public static void main(String[] args) {
        NotificationService service;

        System.out.println("--- Email Service ---");
        service = new EmailNotificationService();
        service.sendNotification("Order #123 confirmed!");

        System.out.println();

        System.out.println("--- SMS Service ---");
        service = new SMSNotificationService();
        service.sendNotification("Your OTP is 9876");
    }
}

// ABSTRACT FACTORY: Creates FAMILIES of related objects.
// India: UPI + GST Receipt + VPA Validator
// US: Credit Card + US Invoice + Luhn Validator
// Can't mix India processor with US receipt -- they vary TOGETHER.
// USE WHEN: products must be CONSISTENT within a theme/region/OS.

// ===== Product Family Interfaces =====
interface PaymentProcessor {
    void charge(double amount);
    String getName();
}

interface Receipt {
    void generate(String txnId, double amount);
}

interface PaymentValidator {
    boolean validate(String details);
}

// ===== India Family =====
class UPIProcessor implements PaymentProcessor {
    public void charge(double amount) {
        System.out.println("  [UPI] Charged Rs." + amount + " via NPCI");
    }
    public String getName() { return "UPI"; }
}

class IndiaReceipt implements Receipt {
    public void generate(String txnId, double amount) {
        double gst = amount * 0.18;
        System.out.println("  [GST Invoice] " + txnId + " | Rs." + amount + " + GST Rs." + String.format("%.2f", gst));
    }
}

class IndiaValidator implements PaymentValidator {
    public boolean validate(String details) {
        boolean ok = details.contains("@");
        System.out.println("  [VPA Check] " + details + " -> " + (ok ? "VALID" : "INVALID"));
        return ok;
    }
}

// ===== US Family =====
class CreditCardProcessor implements PaymentProcessor {
    public void charge(double amount) {
        System.out.println("  [Visa] Charged $" + amount + " via card network");
    }
    public String getName() { return "Credit Card"; }
}

class USReceipt implements Receipt {
    public void generate(String txnId, double amount) {
        System.out.println("  [US Invoice] " + txnId + " | $" + amount + " + state tax");
    }
}

class USValidator implements PaymentValidator {
    public boolean validate(String details) {
        boolean ok = details.length() >= 13;
        System.out.println("  [Luhn] ****" + details.substring(details.length() - 4) + " -> " + (ok ? "VALID" : "INVALID"));
        return ok;
    }
}

// ===== Abstract Factory =====
// WHY: Each country needs ALL THREE products to be consistent.
// IndiaPaymentFactory guarantees: UPI + GST + VPA -- always together.
interface PaymentFactory {
    PaymentProcessor createProcessor();
    Receipt createReceipt();
    PaymentValidator createValidator();
}

class IndiaPaymentFactory implements PaymentFactory {
    public PaymentProcessor createProcessor() { return new UPIProcessor(); }
    public Receipt createReceipt() { return new IndiaReceipt(); }
    public PaymentValidator createValidator() { return new IndiaValidator(); }
}

class USPaymentFactory implements PaymentFactory {
    public PaymentProcessor createProcessor() { return new CreditCardProcessor(); }
    public Receipt createReceipt() { return new USReceipt(); }
    public PaymentValidator createValidator() { return new USValidator(); }
}

// ===== Client -- SAME code works for ANY country =====
class CheckoutService {
    private final PaymentFactory factory;

    CheckoutService(PaymentFactory factory) { this.factory = factory; }

    void checkout(String paymentDetails, double amount) {
        PaymentValidator validator = factory.createValidator();
        PaymentProcessor processor = factory.createProcessor();
        Receipt receipt = factory.createReceipt();

        System.out.println("=== " + processor.getName() + " Checkout ===");
        if (!validator.validate(paymentDetails)) {
            System.out.println("  REJECTED");
            return;
        }
        processor.charge(amount);
        receipt.generate("TXN-" + System.currentTimeMillis(), amount);
        System.out.println("=== Done ===");
    }
}

// Factory of Factories -- selects the right country
class PaymentFactoryProvider {
    public static PaymentFactory getFactory(String country) {
        return switch (country.toUpperCase()) {
            case "INDIA" -> new IndiaPaymentFactory();
            case "US"    -> new USPaymentFactory();
            default -> throw new IllegalArgumentException("Unknown: " + country);
        };
    }
}

public class Main {
    public static void main(String[] args) {
        System.out.println("--- India Checkout ---");
        CheckoutService india = new CheckoutService(PaymentFactoryProvider.getFactory("INDIA"));
        india.checkout("ravi@upi", 999.0);

        System.out.println();

        System.out.println("--- US Checkout ---");
        CheckoutService us = new CheckoutService(PaymentFactoryProvider.getFactory("US"));
        us.checkout("4111111111111234", 49.99);
    }
}
